export enum SimplexStatus {
  OPTIMAL = 'Optimal Solution Found',
  UNBOUNDED = 'Unbounded Solution',
  INFEASIBLE = 'Infeasible Solution',
  IN_PROGRESS = 'In Progress',
  NOT_STARTED = 'Not Started'
}

export interface LPProblem {
  numVariables: number;
  numConstraints: number;
  objective: number[]; // Coefficients of Z = c1x1 + c2x2 ...
  constraints: number[][]; // Matrix of LHS coefficients
  rhs: number[]; // Right hand side values
}

// Represents one state of the Tableau
export interface TableauState {
  stepIndex: number;
  tableau: number[][]; // The full grid including slack variables and Z row
  basicVariables: number[]; // Indices of variables currently in the basis (for each row)
  variableNames: string[]; // Headers like x1, x2, s1, s2, RHS
  pivotRow?: number; // Index of the leaving row
  pivotCol?: number; // Index of the entering column
  enteringVar?: string;
  leavingVar?: string;
  zValue: number;
  description: string;
  status: SimplexStatus;
}

export interface SimplexResult {
  steps: TableauState[];
  finalStatus: SimplexStatus;
}

import { LPProblem, SimplexResult, SimplexStatus, TableauState } from '../types';

/**
 * Solves a Maximization LP problem using the Simplex Method.
 * Converts to standard form by adding slack variables automatically.
 */
export const solveSimplex = (problem: LPProblem): SimplexResult => {
  const { numVariables, numConstraints, objective, constraints, rhs } = problem;

  const steps: TableauState[] = [];

  // 1. Setup Initial Tableau
  // Total columns = numVariables + numConstraints (slacks) + 1 (RHS)
  const totalCols = numVariables + numConstraints + 1;
  const variableNames: string[] = [];
  for (let i = 0; i < numVariables; i++) variableNames.push(`x${i + 1}`);
  for (let i = 0; i < numConstraints; i++) variableNames.push(`s${i + 1}`);
  variableNames.push('RHS');

  // Initialize matrix
  // Rows = numConstraints + 1 (Objective Row at bottom)
  let tableau: number[][] = [];
  const basicVariables: number[] = [];

  // Build Constraint Rows
  for (let i = 0; i < numConstraints; i++) {
    const row: number[] = [];
    // Regular variables
    for (let j = 0; j < numVariables; j++) {
      row.push(constraints[i][j] || 0);
    }
    // Slack variables (Identity matrix part)
    for (let k = 0; k < numConstraints; k++) {
      row.push(i === k ? 1 : 0);
    }
    // RHS
    row.push(rhs[i] || 0);
    tableau.push(row);
    // Initially, slack variables are basic. 
    // Variable indices: 0..numVars-1 are x, numVars..totalCols-2 are s
    basicVariables.push(numVariables + i);
  }

  // Build Objective Row (Z row)
  // In standard form: Z - c1x1 - c2x2... = 0
  // So coefficients are -c1, -c2...
  const zRow: number[] = [];
  for (let j = 0; j < numVariables; j++) {
    zRow.push(-(objective[j] || 0));
  }
  for (let k = 0; k < numConstraints; k++) zRow.push(0); // Slacks in Z are 0
  zRow.push(0); // Initial Z value
  tableau.push(zRow);

  // Initial State Record
  let currentState: TableauState = {
    stepIndex: 0,
    tableau: JSON.parse(JSON.stringify(tableau)),
    basicVariables: [...basicVariables],
    variableNames,
    zValue: tableau[tableau.length - 1][totalCols - 1],
    description: "Initial Tableau constructed. Checking for optimality.",
    status: SimplexStatus.IN_PROGRESS
  };

  // Iteration Loop
  let iteration = 0;
  const MAX_ITERATIONS = 50; // Safety break

  while (iteration < MAX_ITERATIONS) {
    const currentTableau = currentState.tableau;
    const zRowIndex = currentTableau.length - 1;
    const zRowData = currentTableau[zRowIndex];

    // 1. Check Optimality: Are there any negative coefficients in the Z row (excluding RHS)?
    // (For maximization problem converted to Z - Cx = 0 form)
    let minVal = 0;
    let pivotCol = -1;

    for (let j = 0; j < totalCols - 1; j++) {
      if (zRowData[j] < minVal) {
        minVal = zRowData[j];
        pivotCol = j;
      }
    }

    if (pivotCol === -1) {
      // Optimal found
      currentState.status = SimplexStatus.OPTIMAL;
      currentState.description = "All coefficients in Z-row are non-negative. Optimal solution found.";
      steps.push(currentState);
      break;
    }

    // 2. Determine Pivot Row (Minimum Ratio Test)
    let pivotRow = -1;
    let minRatio = Infinity;

    for (let i = 0; i < numConstraints; i++) {
      const valInPivotCol = currentTableau[i][pivotCol];
      const rhsVal = currentTableau[i][totalCols - 1];

      if (valInPivotCol > 0) {
        const ratio = rhsVal / valInPivotCol;
        if (ratio < minRatio) {
          minRatio = ratio;
          pivotRow = i;
        }
      }
    }

    if (pivotRow === -1) {
      // Unbounded
      currentState.status = SimplexStatus.UNBOUNDED;
      currentState.description = "Pivot column has no positive elements. Solution is unbounded.";
      // Mark the entering var for visualization even if we stop
      currentState.pivotCol = pivotCol;
      currentState.enteringVar = variableNames[pivotCol];
      steps.push(currentState);
      break;
    }

    // Record the pivot decision in the CURRENT state before moving to next
    currentState.pivotRow = pivotRow;
    currentState.pivotCol = pivotCol;
    currentState.enteringVar = variableNames[pivotCol];
    currentState.leavingVar = variableNames[currentState.basicVariables[pivotRow]];
    currentState.description = `Pivot Element at [Row ${pivotRow + 1}, Col ${variableNames[pivotCol]}]. Entering: ${currentState.enteringVar}, Leaving: ${currentState.leavingVar}.`;
    steps.push(currentState);

    // 3. Perform Gaussian Elimination to create next state
    const nextTableau = currentTableau.map(row => [...row]); // Deep copy
    const pivotVal = currentTableau[pivotRow][pivotCol];

    // Normalize Pivot Row
    for (let j = 0; j < totalCols; j++) {
      nextTableau[pivotRow][j] = currentTableau[pivotRow][j] / pivotVal;
    }

    // Eliminate other rows
    for (let i = 0; i < currentTableau.length; i++) {
      if (i !== pivotRow) {
        const factor = currentTableau[i][pivotCol];
        for (let j = 0; j < totalCols; j++) {
          nextTableau[i][j] = currentTableau[i][j] - factor * nextTableau[pivotRow][j];
        }
      }
    }

    // Update Basic Variables
    const nextBasicVars = [...currentState.basicVariables];
    nextBasicVars[pivotRow] = pivotCol;

    // Create New State
    iteration++;
    currentState = {
      stepIndex: iteration,
      tableau: nextTableau,
      basicVariables: nextBasicVars,
      variableNames,
      zValue: nextTableau[nextTableau.length - 1][totalCols - 1],
      description: "Tableau updated after row operations.",
      status: SimplexStatus.IN_PROGRESS
    };
  }

  if (iteration === MAX_ITERATIONS) {
     currentState.status = SimplexStatus.UNBOUNDED; // Likely cycling or unbounded
     steps.push(currentState);
  }

  return {
    steps,
    finalStatus: steps[steps.length - 1].status
  };
};

import { GoogleGenAI, Type } from "@google/genai";
import { TableauState } from '../types';

export const generateExplanation = async (state: TableauState): Promise<string> => {
  if (!process.env.API_KEY) return "API Key not found.";

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are a helpful Operations Research tutor.
    Explain the current step of the Simplex Method based on this data:

    Status: ${state.status}
    Objective Value Z: ${state.zValue.toFixed(2)}

    Pivot Decision (if applicable):
    - Entering Variable: ${state.enteringVar || "None"}
    - Leaving Variable: ${state.leavingVar || "None"}

    Current description: ${state.description}

    If the status is OPTIMAL, explain what the final Z value means.
    If IN_PROGRESS, explain why we chose the entering variable (usually most negative in Z-row) and leaving variable (minimum ratio test).
    Keep it concise (max 2 sentences) and encouraging.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return response.text || "Could not generate explanation.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "AI explanation currently unavailable.";
  }
};

export const generateRandomProblem = async (): Promise<any> => {
   if (!process.env.API_KEY) return null;
   const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

   const schema = {
        type: Type.OBJECT,
        properties: {
            numVariables: { type: Type.INTEGER },
            numConstraints: { type: Type.INTEGER },
            objective: { 
                type: Type.ARRAY, 
                items: { type: Type.INTEGER } 
            },
            constraints: { 
                type: Type.ARRAY, 
                items: { 
                    type: Type.ARRAY, 
                    items: { type: Type.INTEGER } 
                } 
            },
            rhs: { 
                type: Type.ARRAY, 
                items: { type: Type.INTEGER } 
            }
        },
        required: ["numVariables", "numConstraints", "objective", "constraints", "rhs"]
   };

   try {
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: "Generate a valid, solvable Linear Programming Maximization problem. It should have 2 or 3 variables and 2 or 3 constraints. Make coefficients small integers (between 1 and 10) to be easy to visualize. Do not make it unbounded.",
        config: {
            responseMimeType: "application/json",
            responseSchema: schema
        }
    });

    return JSON.parse(response.text);
   } catch (e) {
       console.error(e);
       return null;
   }
}

import React from 'react';
import { TableauState } from '../types';

interface TableauProps {
  state: TableauState;
}

export const Tableau: React.FC<TableauProps> = ({ state }) => {
  const { tableau, variableNames, basicVariables, pivotRow, pivotCol } = state;
  const numRows = tableau.length;
  const numCols = tableau[0].length;

  return (
    <div className="overflow-x-auto rounded-lg border border-dark-700 bg-dark-800 shadow-xl">
      <table className="w-full text-sm text-left text-gray-300">
        <thead className="text-xs uppercase bg-dark-900 text-gray-400">
          <tr>
            <th className="px-4 py-3 border-b border-dark-700">Basic Var</th>
            {variableNames.map((name, idx) => (
              <th 
                key={name} 
                className={`px-4 py-3 border-b border-dark-700 text-center ${idx === pivotCol ? 'bg-secondary/20 text-secondary' : ''}`}
              >
                {name}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {tableau.map((row, rowIndex) => {
            const isZRow = rowIndex === numRows - 1;
            const isLeaving = rowIndex === pivotRow;
            // The basic variable for this row (except Z row)
            const basicVarIndex = isZRow ? -1 : basicVariables[rowIndex];
            const basicVarName = isZRow ? 'Z' : variableNames[basicVarIndex];

            return (
              <tr 
                key={rowIndex} 
                className={`
                  border-b border-dark-700 last:border-0 transition-colors duration-300
                  ${isZRow ? 'bg-dark-900/50 font-bold' : ''}
                  ${isLeaving ? 'bg-red-900/20' : ''}
                `}
              >
                <td className="px-4 py-3 font-medium border-r border-dark-700">
                  {basicVarName}
                </td>
                {row.map((cell, colIndex) => {
                  const isPivot = rowIndex === pivotRow && colIndex === pivotCol;
                  const isPivotCol = colIndex === pivotCol;

                  return (
                    <td 
                      key={colIndex} 
                      className={`
                        px-4 py-3 text-center tabular-nums
                        ${isPivot ? 'bg-accent/30 text-accent font-bold ring-1 ring-inset ring-accent' : ''}
                        ${!isPivot && isPivotCol ? 'bg-secondary/10' : ''}
                      `}
                    >
                      {Number.isInteger(cell) ? cell : cell.toFixed(2)}
                    </td>
                  );
                })}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

import React, { useState } from 'react';
import { Plus, Minus, RefreshCw } from 'lucide-react';
import { LPProblem } from '../types';

interface ProblemInputProps {
  initialProblem: LPProblem;
  onSolve: (problem: LPProblem) => void;
  onRandom: () => void;
}

export const ProblemInput: React.FC<ProblemInputProps> = ({ initialProblem, onSolve, onRandom }) => {
  const [numVars, setNumVars] = useState(initialProblem.numVariables);
  const [numConstraints, setNumConstraints] = useState(initialProblem.numConstraints);
  const [objective, setObjective] = useState<number[]>(initialProblem.objective);
  const [constraints, setConstraints] = useState<number[][]>(initialProblem.constraints);
  const [rhs, setRhs] = useState<number[]>(initialProblem.rhs);

  // Helper to safely update array state
  const updateObjective = (idx: number, val: string) => {
    const newObj = [...objective];
    newObj[idx] = Number(val) || 0;
    setObjective(newObj);
  };

  const updateConstraint = (row: number, col: number, val: string) => {
    const newConst = [...constraints];
    if (!newConst[row]) newConst[row] = [];
    newConst[row][col] = Number(val) || 0;
    setConstraints(newConst);
  };

  const updateRhs = (idx: number, val: string) => {
    const newRhs = [...rhs];
    newRhs[idx] = Number(val) || 0;
    setRhs(newRhs);
  };

  const adjustDimensions = (v: number, c: number) => {
    // Resize arrays logic simplified for brevity - in a real app, preserve data better
    const newObj = Array(v).fill(0).map((_, i) => objective[i] || 0);
    const newCons = Array(c).fill(0).map((_, i) => Array(v).fill(0).map((__, j) => (constraints[i] && constraints[i][j]) || 0));
    const newRhs = Array(c).fill(0).map((_, i) => rhs[i] || 0);

    setNumVars(v);
    setNumConstraints(c);
    setObjective(newObj);
    setConstraints(newCons);
    setRhs(newRhs);
  };

  const handleSolve = () => {
    onSolve({
      numVariables: numVars,
      numConstraints,
      objective,
      constraints,
      rhs
    });
  };

  return (
    <div className="bg-dark-800 p-6 rounded-xl border border-dark-700 shadow-lg mb-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <h2 className="text-xl font-bold text-gray-100 flex items-center gap-2">
          <div className="w-2 h-8 bg-primary rounded-full"></div>
          Problem Definition
        </h2>

        <div className="flex gap-4">
            <div className="flex items-center gap-2 bg-dark-900 p-1.5 rounded-lg border border-dark-700">
                <span className="text-xs text-gray-400 px-2">Variables</span>
                <button onClick={() => adjustDimensions(Math.max(2, numVars - 1), numConstraints)} className="p-1 hover:bg-dark-700 rounded"><Minus size={14} /></button>
                <span className="w-6 text-center font-mono">{numVars}</span>
                <button onClick={() => adjustDimensions(Math.min(6, numVars + 1), numConstraints)} className="p-1 hover:bg-dark-700 rounded"><Plus size={14} /></button>
            </div>
            <div className="flex items-center gap-2 bg-dark-900 p-1.5 rounded-lg border border-dark-700">
                <span className="text-xs text-gray-400 px-2">Constraints</span>
                <button onClick={() => adjustDimensions(numVars, Math.max(1, numConstraints - 1))} className="p-1 hover:bg-dark-700 rounded"><Minus size={14} /></button>
                <span className="w-6 text-center font-mono">{numConstraints}</span>
                <button onClick={() => adjustDimensions(numVars, Math.min(6, numConstraints + 1))} className="p-1 hover:bg-dark-700 rounded"><Plus size={14} /></button>
            </div>
             <button 
              onClick={onRandom}
              className="flex items-center gap-2 px-3 py-1.5 bg-dark-700 hover:bg-dark-600 text-gray-300 rounded-lg transition-colors text-sm border border-transparent hover:border-gray-500"
            >
              <RefreshCw size={14} />
              Random
            </button>
        </div>
      </div>

      <div className="space-y-6">
        {/* Objective Function */}
        <div className="flex items-center gap-2 flex-wrap">
          <span className="font-mono text-secondary font-bold text-lg">Max Z = </span>
          {Array.from({ length: numVars }).map((_, i) => (
            <React.Fragment key={i}>
              <input
                type="number"
                value={objective[i]}
                onChange={(e) => updateObjective(i, e.target.value)}
                className="w-16 bg-dark-900 border border-dark-600 rounded p-2 text-center text-white focus:ring-2 focus:ring-primary outline-none"
              />
              <span className="font-mono text-gray-400">x{i + 1}</span>
              {i < numVars - 1 && <span className="text-gray-500">+</span>}
            </React.Fragment>
          ))}
        </div>

        {/* Constraints */}
        <div className="space-y-3">
          <p className="text-xs text-gray-500 uppercase tracking-wider font-semibold">Subject to:</p>
          {Array.from({ length: numConstraints }).map((_, i) => (
            <div key={i} className="flex items-center gap-2 flex-wrap">
              {Array.from({ length: numVars }).map((__, j) => (
                <React.Fragment key={j}>
                  <input
                    type="number"
                    value={constraints[i]?.[j] ?? 0}
                    onChange={(e) => updateConstraint(i, j, e.target.value)}
                    className="w-16 bg-dark-900 border border-dark-600 rounded p-2 text-center text-white focus:ring-2 focus:ring-primary outline-none"
                  />
                  <span className="font-mono text-gray-400">x{j + 1}</span>
                  {j < numVars - 1 && <span className="text-gray-500">+</span>}
                </React.Fragment>
              ))}
              <span className="font-mono text-gray-400 mx-2">≤</span>
              <input
                type="number"
                value={rhs[i] ?? 0}
                onChange={(e) => updateRhs(i, e.target.value)}
                className="w-20 bg-dark-900 border border-dark-600 rounded p-2 text-center text-white focus:ring-2 focus:ring-secondary outline-none"
              />
            </div>
          ))}
        </div>

        <button 
          onClick={handleSolve}
          className="w-full py-3 bg-primary hover:bg-indigo-600 text-white font-semibold rounded-lg shadow-lg shadow-indigo-900/20 transition-all flex justify-center items-center gap-2"
        >
          Generate Simplex Tableaus
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, SkipForward, SkipBack, RotateCcw, 
  Sparkles, CheckCircle, AlertCircle, TrendingUp 
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

import { Tableau } from './components/Tableau';
import { ProblemInput } from './components/ProblemInput';
import { solveSimplex } from './services/simplexEngine';
import { generateExplanation, generateRandomProblem } from './services/geminiService';
import { LPProblem, SimplexResult, SimplexStatus } from './types';

// Default Problem
const DEFAULT_PROBLEM: LPProblem = {
  numVariables: 2,
  numConstraints: 2,
  objective: [3, 4],
  constraints: [
    [1, 2],
    [2, 1]
  ],
  rhs: [10, 8]
};

const App: React.FC = () => {
  const [problem, setProblem] = useState<LPProblem>(DEFAULT_PROBLEM);
  const [result, setResult] = useState<SimplexResult | null>(null);
  const [stepIndex, setStepIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [aiExplanation, setAiExplanation] = useState<string>("");
  const [loadingAi, setLoadingAi] = useState(false);
  const [keySelectorOpen, setKeySelectorOpen] = useState(false);

  const timerRef = useRef<number | null>(null);

  // Initialize with a solution
  useEffect(() => {
    handleSolve(problem);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSolve = (p: LPProblem) => {
    const res = solveSimplex(p);
    setProblem(p);
    setResult(res);
    setStepIndex(0);
    setIsPlaying(false);
    fetchExplanation(res.steps[0]);
  };

  const handleRandom = async () => {
    setLoadingAi(true);
    const newProb = await generateRandomProblem();
    setLoadingAi(false);
    if (newProb) {
        setProblem(newProb); // Update input UI
        handleSolve(newProb); // Auto solve
    }
  };

  const fetchExplanation = async (state: any) => {
    setLoadingAi(true);
    setAiExplanation("");
    const text = await generateExplanation(state);
    setAiExplanation(text);
    setLoadingAi(false);
  };

  const currentStep = result?.steps[stepIndex];

  // Auto-play Logic
  useEffect(() => {
    if (isPlaying && result) {
      timerRef.current = window.setInterval(() => {
        setStepIndex(prev => {
          if (prev < result.steps.length - 1) {
             const next = prev + 1;
             // Don't auto-fetch AI for rapid auto-play, only when paused or manually stepped? 
             // Actually, let's fetch only if it stops.
             return next;
          } else {
            setIsPlaying(false);
            return prev;
          }
        });
      }, 1500); // 1.5s per step
    } else if (timerRef.current) {
      clearInterval(timerRef.current);
    }

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isPlaying, result]);

  // Fetch AI explanation when step changes manually or stops
  useEffect(() => {
    if (currentStep && !isPlaying) {
        fetchExplanation(currentStep);
    }
  }, [stepIndex, isPlaying, result]); // Dependencies need to include result to catch initial load

  const stepForward = () => {
    if (result && stepIndex < result.steps.length - 1) {
      setStepIndex(stepIndex + 1);
    }
  };

  const stepBack = () => {
    if (stepIndex > 0) {
      setStepIndex(stepIndex - 1);
    }
  };

  // Chart Data Preparation
  const chartData = result?.steps.map((s, i) => ({
    step: i,
    z: s.zValue
  })) || [];

  return (
    <div className="min-h-screen bg-dark-900 text-gray-100 font-sans selection:bg-primary selection:text-white pb-20">

      {/* Header */}
      <header className="bg-dark-900/80 backdrop-blur-md border-b border-dark-700 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-white font-bold">
              S
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-gray-100 to-gray-400">
              SimplexFlow
            </h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden md:flex text-sm text-gray-500 gap-4">
                <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-secondary"></span> Entering Var</span>
                <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-red-500"></span> Leaving Var</span>
                <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-accent"></span> Pivot</span>
             </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Top Section: Inputs and Controls */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
          <div className="lg:col-span-1">
             <ProblemInput 
                initialProblem={problem} 
                onSolve={handleSolve}
                onRandom={handleRandom}
             />

             {/* Progress Chart */}
             <div className="bg-dark-800 p-6 rounded-xl border border-dark-700 shadow-lg">
                <h3 className="text-sm font-semibold text-gray-400 mb-4 flex items-center gap-2">
                    <TrendingUp size={16}/> Optimization Path
                </h3>
                <div className="h-40 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <LineChart data={chartData}>
