               <div className="flex items-center gap-3">
                 <span className="text-sm font-mono text-gray-500">Step {stepIndex + 1} / {result?.steps.length}</span>
                 {currentStep?.status === SimplexStatus.OPTIMAL && 
                    <span className="px-2 py-1 bg-secondary/20 text-secondary text-xs rounded-full font-medium flex items-center gap-1">
                        <CheckCircle size={12}/> Optimal
                    </span>
                 }
                 {currentStep?.status === SimplexStatus.UNBOUNDED && 
                    <span className="px-2 py-1 bg-red-500/20 text-red-500 text-xs rounded-full font-medium flex items-center gap-1">
                        <AlertCircle size={12}/> Unbounded
                    </span>
                 }
               </div>

               {/* Playback Controls */}
               <div className="flex items-center gap-2">
                 <button onClick={() => { setIsPlaying(false); setStepIndex(0); }} className="p-2 hover:bg-dark-700 rounded-lg text-gray-400 hover:text-white transition-colors">
                    <RotateCcw size={18} />
                 </button>
                 <button onClick={stepBack} disabled={stepIndex === 0} className="p-2 hover:bg-dark-700 rounded-lg text-gray-400 hover:text-white disabled:opacity-30 transition-colors">
                    <SkipBack size={18} />
