                 <button 
                    onClick={() => setIsPlaying(!isPlaying)} 
                    className={`p-2 rounded-lg transition-colors text-white ${isPlaying ? 'bg-red-500 hover:bg-red-600' : 'bg-primary hover:bg-primary/90'}`}
                 >
                    {isPlaying ? <Pause size={18} fill="currentColor"/> : <Play size={18} fill="currentColor"/>}
                 </button>
                 <button onClick={stepForward} disabled={!result || stepIndex === result.steps.length - 1} className="p-2 hover:bg-dark-700 rounded-lg text-gray-400 hover:text-white disabled:opacity-30 transition-colors">
                    <SkipForward size={18} />
                 </button>
               </div>
            </div>

            {/* The Tableau */}
            {currentStep && <Tableau state={currentStep} />}

            {/* AI Explanation Box */}
            <div className="bg-gradient-to-r from-dark-800 to-dark-800/50 p-6 rounded-xl border border-dark-700 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-10">
