export enum SimplexStatus {
  OPTIMAL = '找到最优解 (Optimal)',
  UNBOUNDED = '解无界 (Unbounded)',
  INFEASIBLE = '无可行解 (Infeasible)',
  IN_PROGRESS = '计算中 (In Progress)',
  NOT_STARTED = '未开始'
}

export interface LPProblem {
  numVariables: number;
  numConstraints: number;
  objective: number[]; // Coefficients of Z = c1x1 + c2x2 ...
  constraints: number[][]; // Matrix of LHS coefficients
  rhs: number[]; // Right hand side values
}

// Represents one state of the Tableau
export interface TableauState {
  stepIndex: number;
  tableau: number[][]; // The full grid including slack variables and Z row
  basicVariables: number[]; // Indices of variables currently in the basis (for each row)
  variableNames: string[]; // Headers like x1, x2, s1, s2, RHS
  pivotRow?: number; // Index of the leaving row
  pivotCol?: number; // Index of the entering column
  enteringVar?: string;
  leavingVar?: string;
  zValue: number;
  description: string;
  status: SimplexStatus;
}

export interface SimplexResult {
  steps: TableauState[];
  finalStatus: SimplexStatus;
}

export type AIProvider = 'gemini' | 'deepseek';

export interface AIConfig {
  provider: AIProvider;
  deepSeekKey?: string; // Optional, handled via UI input
}

import { LPProblem, SimplexResult, SimplexStatus, TableauState } from '../types';

/**
 * Solves a Maximization LP problem using the Simplex Method.
 * Converts to standard form by adding slack variables automatically.
 */
export const solveSimplex = (problem: LPProblem): SimplexResult => {
  const { numVariables, numConstraints, objective, constraints, rhs } = problem;

  const steps: TableauState[] = [];

  // 1. Setup Initial Tableau
  // Total columns = numVariables + numConstraints (slacks) + 1 (RHS)
  const totalCols = numVariables + numConstraints + 1;
  const variableNames: string[] = [];
  for (let i = 0; i < numVariables; i++) variableNames.push(`x${i + 1}`);
  for (let i = 0; i < numConstraints; i++) variableNames.push(`s${i + 1}`);
  variableNames.push('RHS');

  // Initialize matrix
  // Rows = numConstraints + 1 (Objective Row at bottom)
  let tableau: number[][] = [];
  const basicVariables: number[] = [];

  // Build Constraint Rows
  for (let i = 0; i < numConstraints; i++) {
    const row: number[] = [];
    // Regular variables
    for (let j = 0; j < numVariables; j++) {
      row.push(constraints[i][j] || 0);
    }
    // Slack variables (Identity matrix part)
    for (let k = 0; k < numConstraints; k++) {
      row.push(i === k ? 1 : 0);
    }
    // RHS
    row.push(rhs[i] || 0);
    tableau.push(row);
    // Initially, slack variables are basic. 
    // Variable indices: 0..numVars-1 are x, numVars..totalCols-2 are s
    basicVariables.push(numVariables + i);
  }

  // Build Objective Row (Z row)
  // In standard form: Z - c1x1 - c2x2... = 0
  // So coefficients are -c1, -c2...
  const zRow: number[] = [];
  for (let j = 0; j < numVariables; j++) {
    zRow.push(-(objective[j] || 0));
  }
  for (let k = 0; k < numConstraints; k++) zRow.push(0); // Slacks in Z are 0
  zRow.push(0); // Initial Z value
  tableau.push(zRow);

  // Initial State Record
  let currentState: TableauState = {
    stepIndex: 0,
    tableau: JSON.parse(JSON.stringify(tableau)),
    basicVariables: [...basicVariables],
    variableNames,
    zValue: tableau[tableau.length - 1][totalCols - 1],
    description: "构建初始单纯形表。正在检查最优性。",
    status: SimplexStatus.IN_PROGRESS
  };

  // Iteration Loop
  let iteration = 0;
  const MAX_ITERATIONS = 50; // Safety break

  while (iteration < MAX_ITERATIONS) {
    const currentTableau = currentState.tableau;
    const zRowIndex = currentTableau.length - 1;
    const zRowData = currentTableau[zRowIndex];

    // 1. Check Optimality: Are there any negative coefficients in the Z row (excluding RHS)?
    // (For maximization problem converted to Z - Cx = 0 form)
    let minVal = 0;
    let pivotCol = -1;

    for (let j = 0; j < totalCols - 1; j++) {
      if (zRowData[j] < minVal) {
        minVal = zRowData[j];
        pivotCol = j;
      }
    }

    if (pivotCol === -1) {
      // Optimal found
      currentState.status = SimplexStatus.OPTIMAL;
      currentState.description = "Z行所有系数均为非负，已找到最优解。";
      steps.push(currentState);
      break;
    }

    // 2. Determine Pivot Row (Minimum Ratio Test)
    let pivotRow = -1;
    let minRatio = Infinity;

    for (let i = 0; i < numConstraints; i++) {
      const valInPivotCol = currentTableau[i][pivotCol];
      const rhsVal = currentTableau[i][totalCols - 1];

      if (valInPivotCol > 0) {
        const ratio = rhsVal / valInPivotCol;
        if (ratio < minRatio) {
          minRatio = ratio;
          pivotRow = i;
        }
      }
    }

    if (pivotRow === -1) {
      // Unbounded
      currentState.status = SimplexStatus.UNBOUNDED;
      currentState.description = "入基变量列中没有正数，解无界。";
      // Mark the entering var for visualization even if we stop
      currentState.pivotCol = pivotCol;
      currentState.enteringVar = variableNames[pivotCol];
      steps.push(currentState);
      break;
    }

    // Record the pivot decision in the CURRENT state before moving to next
    currentState.pivotRow = pivotRow;
    currentState.pivotCol = pivotCol;
    currentState.enteringVar = variableNames[pivotCol];
    currentState.leavingVar = variableNames[currentState.basicVariables[pivotRow]];
    currentState.description = `主元位置: [行 ${pivotRow + 1}, 列 ${variableNames[pivotCol]}]. 入基: ${currentState.enteringVar}, 出基: ${currentState.leavingVar}.`;
    steps.push(currentState);

    // 3. Perform Gaussian Elimination to create next state
    const nextTableau = currentTableau.map(row => [...row]); // Deep copy
    const pivotVal = currentTableau[pivotRow][pivotCol];

    // Normalize Pivot Row
    for (let j = 0; j < totalCols; j++) {
      nextTableau[pivotRow][j] = currentTableau[pivotRow][j] / pivotVal;
    }

    // Eliminate other rows
    for (let i = 0; i < currentTableau.length; i++) {
      if (i !== pivotRow) {
        const factor = currentTableau[i][pivotCol];
        for (let j = 0; j < totalCols; j++) {
          nextTableau[i][j] = currentTableau[i][j] - factor * nextTableau[pivotRow][j];
        }
      }
    }

    // Update Basic Variables
    const nextBasicVars = [...currentState.basicVariables];
    nextBasicVars[pivotRow] = pivotCol;

    // Create New State
    iteration++;
    currentState = {
      stepIndex: iteration,
      tableau: nextTableau,
      basicVariables: nextBasicVars,
      variableNames,
      zValue: nextTableau[nextTableau.length - 1][totalCols - 1],
      description: "行变换后的新单纯形表。",
      status: SimplexStatus.IN_PROGRESS
    };
  }

  if (iteration === MAX_ITERATIONS) {
     currentState.status = SimplexStatus.UNBOUNDED; // Likely cycling or unbounded
     steps.push(currentState);
  }

  return {
    steps,
    finalStatus: steps[steps.length - 1].status
  };
};

import { GoogleGenAI, Type } from "@google/genai";
import { TableauState, AIConfig } from '../types';

// Helper to get Gemini Client with the selected key
const getGeminiClient = () => {
  const apiKey = process.env.API_KEY; 
  if (!apiKey) throw new Error("请先选择 Google API Key。");
  return new GoogleGenAI({ apiKey });
};

export const generateExplanation = async (state: TableauState, config: AIConfig): Promise<string> => {
  const prompt = `
    你是一位乐于助人的运筹学导师。请用中文解释单纯形法当前的步骤。

    状态数据:
    - 状态: ${state.status}
    - 目标函数值 Z: ${state.zValue.toFixed(2)}

    迭代决策 (如果适用):
    - 入基变量: ${state.enteringVar || "无"}
    - 出基变量: ${state.leavingVar || "无"}
    - 步骤描述: ${state.description}

    如果是“最优解”，请解释最终Z值的含义。
    如果是“计算中”，请解释为什么选择该入基变量（通常是Z行中负值最大）和出基变量（最小比值检验）。
    请保持简洁（不超过2句话），语气鼓励。
  `;

  try {
    if (config.provider === 'deepseek') {
      if (!config.deepSeekKey) return "请在设置中输入 DeepSeek API Key。";

      const response = await fetch("https://api.deepseek.com/chat/completions", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${config.deepSeekKey}`
        },
        body: JSON.stringify({
          model: "deepseek-chat",
          messages: [
            { role: "system", content: "你是一位乐于助人的数学导师。" },
            { role: "user", content: prompt }
          ],
          stream: false
        })
      });

      if (!response.ok) throw new Error(`DeepSeek API 错误: ${response.statusText}`);
      const data = await response.json();
      return data.choices[0]?.message?.content || "未返回解释。";

    } else {
      // Gemini Logic
      const ai = getGeminiClient();
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
      });
      return response.text || "无法生成解释。";
    }
  } catch (error: any) {
    console.error("AI Error:", error);
    return `AI 错误: ${error.message || "未知错误"}`;
  }
};

export const generateRandomProblem = async (config: AIConfig): Promise<any> => {
   const schema = {
        type: Type.OBJECT,
        properties: {
            numVariables: { type: Type.INTEGER },
            numConstraints: { type: Type.INTEGER },
            objective: { 
                type: Type.ARRAY, 
                items: { type: Type.INTEGER } 
            },
            constraints: { 
                type: Type.ARRAY, 
                items: { 
                    type: Type.ARRAY, 
                    items: { type: Type.INTEGER } 
                } 
            },
            rhs: { 
                type: Type.ARRAY, 
                items: { type: Type.INTEGER } 
            }
        },
        required: ["numVariables", "numConstraints", "objective", "constraints", "rhs"]
   };

   const userPrompt = "生成一个有效、可解的线性规划最大化问题。包含2或3个变量，2或3个约束。系数应为1到10之间的小整数，以便于可视化。不要生成无界解的问题。";

   try {
    if (config.provider === 'deepseek') {
        if (!config.deepSeekKey) return null;

        const response = await fetch("https://api.deepseek.com/chat/completions", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "Authorization": `Bearer ${config.deepSeekKey}`
            },
            body: JSON.stringify({
              model: "deepseek-chat",
              messages: [
                { role: "system", content: "你是一个数学题目生成器。只输出有效的JSON。" },
                { role: "user", content: userPrompt + " 只返回符合此结构的JSON对象: {numVariables: int, numConstraints: int, objective: [int], constraints: [[int]], rhs: [int]}." }
              ]
            })
        });
        const data = await response.json();
        const content = data.choices[0]?.message?.content;
        const jsonStr = content.replace(/```json/g, '').replace(/```/g, '').trim();
        return JSON.parse(jsonStr);

    } else {
        // Gemini
        const ai = getGeminiClient();
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: userPrompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema
            }
        });
        return JSON.parse(response.text);
    }
   } catch (e) {
       console.error(e);
       return null;
   }
}

import React, { useState } from 'react';
import { Plus, Minus, RefreshCw, Shuffle } from 'lucide-react';
import { LPProblem } from '../types';

interface ProblemInputProps {
  initialProblem: LPProblem;
  onSolve: (problem: LPProblem) => void;
  onRandom: () => void;
}

export const ProblemInput: React.FC<ProblemInputProps> = ({ initialProblem, onSolve, onRandom }) => {
  const [numVars, setNumVars] = useState(initialProblem.numVariables);
  const [numConstraints, setNumConstraints] = useState(initialProblem.numConstraints);
  const [objective, setObjective] = useState<number[]>(initialProblem.objective);
  const [constraints, setConstraints] = useState<number[][]>(initialProblem.constraints);
  const [rhs, setRhs] = useState<number[]>(initialProblem.rhs);

  // Helper: Get random integer between 1 and 10
  const getRandomInt = () => Math.floor(Math.random() * 10) + 1;

  // Helper to safely update array state
  const updateObjective = (idx: number, val: string) => {
    const newObj = [...objective];
    newObj[idx] = Number(val) || 0;
    setObjective(newObj);
  };

  const updateConstraint = (row: number, col: number, val: string) => {
    const newConst = [...constraints];
    if (!newConst[row]) newConst[row] = [];
    newConst[row][col] = Number(val) || 0;
    setConstraints(newConst);
  };

  const updateRhs = (idx: number, val: string) => {
    const newRhs = [...rhs];
    newRhs[idx] = Number(val) || 0;
    setRhs(newRhs);
  };

  // When dimensions change, fill new slots with RANDOM numbers instead of 0
  const adjustDimensions = (v: number, c: number) => {
    // Preserve existing data where possible, but if expanding, use random
    const newObj = Array(v).fill(0).map((_, i) => (i < objective.length ? objective[i] : getRandomInt()));

    const newCons = Array(c).fill(0).map((_, i) => 
        Array(v).fill(0).map((__, j) => {
            if (constraints[i] && constraints[i][j] !== undefined) return constraints[i][j];
            return getRandomInt();
        })
    );

    const newRhs = Array(c).fill(0).map((_, i) => (i < rhs.length ? rhs[i] : getRandomInt() * 5)); // RHS slightly larger

    setNumVars(v);
    setNumConstraints(c);
    setObjective(newObj);
    setConstraints(newCons);
    setRhs(newRhs);
  };

  // Randomize all coefficients for current size
  const randomizeValues = () => {
      const newObj = objective.map(() => getRandomInt());
      const newCons = constraints.map(row => row.map(() => getRandomInt()));
      const newRhs = rhs.map(() => getRandomInt() * 5 + 10);
      setObjective(newObj);
      setConstraints(newCons);
      setRhs(newRhs);
  };

  const handleSolve = () => {
    onSolve({
      numVariables: numVars,
      numConstraints,
      objective,
      constraints,
      rhs
    });
  };

  return (
    <div className="bg-white p-6 rounded-xl border border-surface-200 shadow-sm mb-6">
      <div className="flex flex-col gap-4 mb-6">
        <div className="flex justify-between items-center">
            <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <div className="w-1.5 h-6 bg-primary rounded-full"></div>
            线性规划设置
            </h2>

            <div className="flex gap-2">
                <button 
                    onClick={randomizeValues}
                    className="flex items-center gap-2 px-3 py-1.5 bg-surface-100 hover:bg-surface-200 text-slate-600 rounded-lg transition-colors text-sm font-medium"
                    title="保留当前行列数，随机生成数据"
                >
                    <Shuffle size={14} />
                    重置数据
                </button>
                <button 
                    onClick={onRandom}
                    className="flex items-center gap-2 px-3 py-1.5 bg-surface-100 hover:bg-surface-200 text-slate-600 rounded-lg transition-colors text-sm font-medium"
                    title="完全随机生成新的问题"
                >
                    <RefreshCw size={14} />
                    随机题目
                </button>
            </div>
        </div>

        {/* Dimensions Controls */}
        <div className="flex flex-wrap gap-4 p-4 bg-surface-50 rounded-lg border border-surface-100">
            <div className="flex items-center gap-3">
                <span className="text-sm font-semibold text-slate-500 uppercase tracking-wide text-xs">变量数 (Variables)</span>
                <div className="flex items-center bg-white rounded-md border border-surface-200 shadow-sm">
                    <button onClick={() => adjustDimensions(Math.max(2, numVars - 1), numConstraints)} className="p-2 hover:bg-surface-50 text-slate-600"><Minus size={14} /></button>
                    <span className="w-8 text-center font-mono font-bold text-slate-800">{numVars}</span>
                    <button onClick={() => adjustDimensions(Math.min(6, numVars + 1), numConstraints)} className="p-2 hover:bg-surface-50 text-slate-600"><Plus size={14} /></button>
                </div>
            </div>
            <div className="w-px h-8 bg-surface-200 hidden sm:block"></div>
            <div className="flex items-center gap-3">
                <span className="text-sm font-semibold text-slate-500 uppercase tracking-wide text-xs">约束数 (Constraints)</span>
                <div className="flex items-center bg-white rounded-md border border-surface-200 shadow-sm">
                    <button onClick={() => adjustDimensions(numVars, Math.max(1, numConstraints - 1))} className="p-2 hover:bg-surface-50 text-slate-600"><Minus size={14} /></button>
                    <span className="w-8 text-center font-mono font-bold text-slate-800">{numConstraints}</span>
                    <button onClick={() => adjustDimensions(numVars, Math.min(6, numConstraints + 1))} className="p-2 hover:bg-surface-50 text-slate-600"><Plus size={14} /></button>
                </div>
            </div>
        </div>
      </div>

      <div className="space-y-6">
        {/* Objective Function */}
        <div className="p-4 rounded-lg bg-blue-50/50 border border-blue-100">
            <div className="flex items-center gap-2 flex-wrap">
            <span className="font-mono text-primary font-bold text-lg">目标函数 Max Z = </span>
            {Array.from({ length: numVars }).map((_, i) => (
                <React.Fragment key={i}>
                <input
                    type="number"
                    value={objective[i]}
                    onChange={(e) => updateObjective(i, e.target.value)}
                    className="w-16 bg-white border border-surface-200 rounded p-2 text-center text-slate-800 font-medium focus:ring-2 focus:ring-primary focus:border-primary outline-none shadow-sm transition-all"
                />
                <span className="font-mono text-slate-400 font-bold">x{i + 1}</span>
                {i < numVars - 1 && <span className="text-slate-400 font-bold">+</span>}
                </React.Fragment>
            ))}
            </div>
        </div>

        {/* Constraints */}
        <div className="space-y-3 pl-2">
          <p className="text-xs text-slate-400 uppercase tracking-wider font-bold">约束条件 (Subject to):</p>
          {Array.from({ length: numConstraints }).map((_, i) => (
            <div key={i} className="flex items-center gap-2 flex-wrap">
              {Array.from({ length: numVars }).map((__, j) => (
                <React.Fragment key={j}>
                  <input
                    type="number"
                    value={constraints[i]?.[j] ?? 0}
                    onChange={(e) => updateConstraint(i, j, e.target.value)}
                    className="w-16 bg-white border border-surface-200 rounded p-2 text-center text-slate-700 focus:ring-2 focus:ring-secondary focus:border-secondary outline-none shadow-sm"
                  />
                  <span className="font-mono text-slate-400">x{j + 1}</span>
                  {j < numVars - 1 && <span className="text-slate-300">+</span>}
                </React.Fragment>
              ))}
              <span className="font-mono text-slate-400 mx-2">≤</span>
              <input
                type="number"
                value={rhs[i] ?? 0}
                onChange={(e) => updateRhs(i, e.target.value)}
                className="w-20 bg-white border border-surface-200 rounded p-2 text-center text-slate-700 font-medium focus:ring-2 focus:ring-secondary focus:border-secondary outline-none shadow-sm"
              />
            </div>
          ))}
        </div>

        <button 
          onClick={handleSolve}
          className="w-full py-3 mt-4 bg-primary hover:bg-blue-600 text-white font-semibold rounded-lg shadow-md shadow-blue-500/20 transition-all flex justify-center items-center gap-2 active:scale-[0.98]"
        >
          生成单纯形表并求解
        </button>
      </div>
    </div>
  );
};

import React from 'react';
import { TableauState } from '../types';

interface TableauProps {
  state: TableauState;
}

export const Tableau: React.FC<TableauProps> = ({ state }) => {
  const { tableau, variableNames, basicVariables, pivotRow, pivotCol } = state;
  const numRows = tableau.length;

  return (
    <div className="overflow-x-auto rounded-lg border border-surface-200 bg-white shadow-lg">
      <table className="w-full text-sm text-left text-slate-600">
        <thead className="text-xs uppercase bg-surface-50 text-slate-500 font-semibold tracking-wider">
          <tr>
            <th className="px-4 py-3 border-b border-surface-200">基变量 (Basic)</th>
            {variableNames.map((name, idx) => (
              <th 
                key={name} 
                className={`px-4 py-3 border-b border-surface-200 text-center ${idx === pivotCol ? 'bg-emerald-50 text-emerald-600' : ''}`}
              >
                {name === 'RHS' ? '右端项 (RHS)' : name}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {tableau.map((row, rowIndex) => {
            const isZRow = rowIndex === numRows - 1;
            const isLeaving = rowIndex === pivotRow;
            const basicVarIndex = isZRow ? -1 : basicVariables[rowIndex];
            const basicVarName = isZRow ? 'Z' : variableNames[basicVarIndex];

            return (
              <tr 
                key={rowIndex} 
                className={`
                  border-b border-surface-100 last:border-0 transition-colors duration-300
                  ${isZRow ? 'bg-surface-50 font-bold text-slate-800 border-t-2 border-t-surface-200' : ''}
                  ${isLeaving ? 'bg-red-50' : ''}
                `}
              >
                <td className="px-4 py-3 font-medium border-r border-surface-100 bg-surface-50/50">
                  {basicVarName}
                </td>
                {row.map((cell, colIndex) => {
                  const isPivot = rowIndex === pivotRow && colIndex === pivotCol;
                  const isPivotCol = colIndex === pivotCol;

                  return (
                    <td 
                      key={colIndex} 
                      className={`
                        px-4 py-3 text-center tabular-nums
                        ${isPivot ? 'bg-amber-100 text-amber-700 font-bold ring-2 ring-inset ring-amber-200' : ''}
                        ${!isPivot && isPivotCol ? 'bg-emerald-50/50' : ''}
                        ${isZRow && !isPivot ? 'text-slate-900' : ''}
                      `}
                    >
                      {Number.isInteger(cell) ? cell : cell.toFixed(2)}
                    </td>
                  );
                })}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, SkipForward, SkipBack, RotateCcw, 
  Sparkles, CheckCircle, AlertCircle, TrendingUp, Settings, Key
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

import { Tableau } from './components/Tableau';
import { ProblemInput } from './components/ProblemInput';
import { solveSimplex } from './services/simplexEngine';
import { generateExplanation, generateRandomProblem } from './services/geminiService';
import { LPProblem, SimplexResult, SimplexStatus, AIConfig, AIProvider } from './types';

// Default Problem
const DEFAULT_PROBLEM: LPProblem = {
  numVariables: 2,
  numConstraints: 2,
  objective: [3, 4],
  constraints: [
    [1, 2],
    [2, 1]
  ],
  rhs: [10, 8]
};

const App: React.FC = () => {
  const [problem, setProblem] = useState<LPProblem>(DEFAULT_PROBLEM);
  const [result, setResult] = useState<SimplexResult | null>(null);
  const [stepIndex, setStepIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [aiExplanation, setAiExplanation] = useState<string>("");
  const [loadingAi, setLoadingAi] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  // AI Config State
  const [aiConfig, setAiConfig] = useState<AIConfig>({
    provider: 'gemini',
    deepSeekKey: ''
  });

  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    handleSolve(problem);
  }, []);

  const handleSolve = (p: LPProblem) => {
    const res = solveSimplex(p);
    setProblem(p);
    setResult(res);
    setStepIndex(0);
    setIsPlaying(false);
    fetchExplanation(res.steps[0]);
  };

  const handleGeminiKeySelection = async () => {
    if (window.aistudio) {
        await window.aistudio.openSelectKey();
    }
  };

  const handleRandom = async () => {
    setLoadingAi(true);
    // Ensure key is ready for Gemini
    if (aiConfig.provider === 'gemini' && window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) await handleGeminiKeySelection();
    }
    // DeepSeek check
    if (aiConfig.provider === 'deepseek' && !aiConfig.deepSeekKey) {
        setAiExplanation("请先在设置中配置 DeepSeek API Key。");
        setLoadingAi(false);
        return;
    }

    const newProb = await generateRandomProblem(aiConfig);
    setLoadingAi(false);
    if (newProb) {
        setProblem(newProb);
        handleSolve(newProb);
    }
  };

  const fetchExplanation = async (state: any) => {
    setLoadingAi(true);
    setAiExplanation("");

    // Key Check
    if (aiConfig.provider === 'gemini' && window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
             setAiExplanation("请在设置中选择 Google API Key 以获取 AI 解释。");
             setLoadingAi(false);
             return;
        }
    }
    if (aiConfig.provider === 'deepseek' && !aiConfig.deepSeekKey) {
         setAiExplanation("请在设置中输入 DeepSeek API Key 以获取 AI 解释。");
         setLoadingAi(false);
         return;
    }

    const text = await generateExplanation(state, aiConfig);
    setAiExplanation(text);
    setLoadingAi(false);
  };

  const currentStep = result?.steps[stepIndex];

  // Auto-play Logic
  useEffect(() => {
    if (isPlaying && result) {
