                        onChange={(e) => setCustomQuestion(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSendQuestion()}
                        placeholder="例如：为什么要选择 x2 入基？"
                        className="flex-1 px-3 py-2 bg-surface-50 border border-surface-200 rounded-lg text-sm focus:ring-1 focus:ring-primary outline-none"
                    />
                    <button 
                        onClick={handleSendQuestion}
                        disabled={loading || !customQuestion.trim() || !state}
                        className="p-2 bg-primary hover:bg-blue-600 text-white rounded-lg transition-colors disabled:opacity-50"
                    >
                        <Send size={18} />
                    </button>
                </div>
            )}

            {/* Key Status Indicator */}
            {!hasKey && (
                <div className="mt-2 text-xs text-red-500 text-center flex items-center justify-center gap-1">
                    <AlertCircle size={12} />
                    请点击齿轮图标配置 API Key
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, SkipForward, SkipBack, RotateCcw, 
  CheckCircle, AlertCircle, TrendingUp
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

import { Tableau } from './components/Tableau';
import { ProblemInput } from './components/ProblemInput';
import { AIInsightPanel } from './components/AIInsightPanel';
import { solveSimplex } from './services/simplexEngine';
import { generateExplanation, generateRandomProblem, askAIQuestion } from './services/geminiService';
import { LPProblem, SimplexResult, SimplexStatus, AIConfig } from './types';

// Default Problem
const DEFAULT_PROBLEM: LPProblem = {
  numVariables: 2,
  numConstraints: 2,
  objective: [3, 4],
  constraints: [
    [1, 2],
    [2, 1]
  ],
  rhs: [10, 8]
};

const App: React.FC = () => {
  const [problem, setProblem] = useState<LPProblem>(DEFAULT_PROBLEM);
  const [result, setResult] = useState<SimplexResult | null>(null);
  const [stepIndex, setStepIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  // AI State
  const [aiExplanation, setAiExplanation] = useState<string>("");
  const [loadingAi, setLoadingAi] = useState(false);
  const [aiConfig, setAiConfig] = useState<AIConfig>({
    provider: 'gemini',
    deepSeekKey: ''
  });

  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    handleSolve(problem);
  }, []);

  const handleSolve = (p: LPProblem) => {
    const res = solveSimplex(p);
    setProblem(p);
    setResult(res);
    setStepIndex(0);
    setIsPlaying(false);
    // Reset explanation on new solve
    setAiExplanation("");
  };

  const handleGeminiKeySelection = async () => {
    if (window.aistudio) {
        await window.aistudio.openSelectKey();
    }
  };

  const checkKeyReady = async (): Promise<boolean> => {
    if (aiConfig.provider === 'gemini') {
        if (window.aistudio) {
             const hasKey = await window.aistudio.hasSelectedApiKey();
             if (!hasKey) {
                 setAiExplanation("请在 AI 洞察面板中点击齿轮图标，配置 Google API Key。");
                 return false;
             }
             return true;
        }
        return false;
    } else {
        if (!aiConfig.deepSeekKey) {
            setAiExplanation("请在 AI 洞察面板中点击齿轮图标，输入 DeepSeek API Key。");
            return false;
        }
        return true;
    }
  };

  const handleRandom = async () => {
    setLoadingAi(true);
    const ready = await checkKeyReady();
    if (!ready) {
        setLoadingAi(false);
        return;
    }

    const newProb = await generateRandomProblem(aiConfig);
    setLoadingAi(false);
    if (newProb) {
        setProblem(newProb);
        handleSolve(newProb);
    }
  };

  const fetchExplanation = async () => {
    const state = result?.steps[stepIndex];
    if (!state) return;

    setLoadingAi(true);
    const ready = await checkKeyReady();
    if (!ready) {
        setLoadingAi(false);
        return;
    }

    const text = await generateExplanation(state, aiConfig);
    setAiExplanation(text);
    setLoadingAi(false);
  };

  const handleAskQuestion = async (question: string) => {
    const state = result?.steps[stepIndex];
    if (!state) return;

    setLoadingAi(true);
    const ready = await checkKeyReady();
    if (!ready) {
        setLoadingAi(false);
        return;
    }

    const text = await askAIQuestion(question, state, aiConfig);
    setAiExplanation(text);
    setLoadingAi(false);
  }

  const currentStep = result?.steps[stepIndex];

  // Auto-play Logic
  useEffect(() => {
    if (isPlaying && result) {
      timerRef.current = window.setInterval(() => {
        setStepIndex(prev => {
          if (prev < result.steps.length - 1) {
             return prev + 1;
          } else {
            setIsPlaying(false);
            return prev;
          }
        });
      }, 1500); 
    } else if (timerRef.current) {
      clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isPlaying, result]);

  const stepForward = () => result && stepIndex < result.steps.length - 1 && setStepIndex(stepIndex + 1);
  const stepBack = () => stepIndex > 0 && setStepIndex(stepIndex - 1);

  const chartData = result?.steps.map((s, i) => ({ step: i, z: s.zValue })) || [];

  return (
    <div className="min-h-screen bg-surface-50 text-slate-800 font-sans pb-20">

      {/* Header */}
      <header className="bg-white border-b border-surface-200 sticky top-0 z-50 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center text-white font-bold shadow-md shadow-blue-500/30">
              S
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">
              单纯形<span className="text-primary">可视化</span> (SimplexFlow)
            </h1>
          </div>
          <div className="hidden md:flex text-sm text-slate-500 gap-4 font-medium">
             <span className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full bg-emerald-500"></span> 入基变量</span>
             <span className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full bg-red-500"></span> 出基变量</span>
             <span className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full bg-amber-500"></span> 主元</span>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
          {/* Left Column: Controls & Charts */}
          <div className="lg:col-span-1 space-y-6">
             <ProblemInput 
                initialProblem={problem} 
                onSolve={handleSolve}
                onRandom={handleRandom}
             />

             {/* Progress Chart */}
             <div className="bg-white p-6 rounded-xl border border-surface-200 shadow-sm">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wide mb-4 flex items-center gap-2">
                    <TrendingUp size={16} className="text-primary"/> 优化路径 (Objective Z)
                </h3>
                <div className="h-40 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <LineChart data={chartData}>
                            <XAxis dataKey="step" hide />
                            <YAxis width={30} stroke="#94a3b8" fontSize={10} tickFormatter={(v) => v.toFixed(1)}/>
                            <Tooltip 
                                contentStyle={{backgroundColor: '#fff', border: '1px solid #e2e8f0', borderRadius: '8px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                                itemStyle={{color: '#3b82f6', fontWeight: 600}}
                            />
                            <Line 
                                type="monotone" 
                                dataKey="z" 
                                stroke="#3b82f6" 
                                strokeWidth={3} 
                                dot={{fill: '#3b82f6', strokeWidth: 2, r: 4}} 
                                activeDot={{r: 6, stroke: '#fff', strokeWidth: 2}} 
                            />
                        </LineChart>
                    </ResponsiveContainer>
                </div>
             </div>
          </div>

          {/* Right Column: Visualization & AI */}
          <div className="lg:col-span-2 space-y-6 flex flex-col">

            {/* Status Bar */}
            <div className="flex items-center justify-between bg-white p-4 rounded-xl border border-surface-200 shadow-sm">
               <div className="flex items-center gap-3">
                 <span className="text-sm font-mono font-semibold text-slate-500 bg-surface-100 px-3 py-1 rounded-md">步骤 {stepIndex + 1} / {result?.steps.length}</span>
                 {currentStep?.status === SimplexStatus.OPTIMAL && 
                    <span className="px-3 py-1 bg-emerald-100 text-emerald-700 text-xs rounded-full font-bold flex items-center gap-1.5 border border-emerald-200">
                        <CheckCircle size={14}/> 最优解
                    </span>
                 }
                 {currentStep?.status === SimplexStatus.UNBOUNDED && 
                    <span className="px-3 py-1 bg-red-100 text-red-700 text-xs rounded-full font-bold flex items-center gap-1.5 border border-red-200">
                        <AlertCircle size={14}/> 解无界
                    </span>
                 }
               </div>

               {/* Playback Controls */}
               <div className="flex items-center gap-2">
                 <button onClick={() => { setIsPlaying(false); setStepIndex(0); }} className="p-2 hover:bg-surface-100 rounded-lg text-slate-400 hover:text-slate-700 transition-colors" title="重置">
                    <RotateCcw size={20} />
                 </button>
                 <button onClick={stepBack} disabled={stepIndex === 0} className="p-2 hover:bg-surface-100 rounded-lg text-slate-400 hover:text-slate-700 disabled:opacity-30 transition-colors" title="上一步">
                    <SkipBack size={20} />
                 </button>
                 <button 
                    onClick={() => setIsPlaying(!isPlaying)} 
                    className={`p-2.5 rounded-lg transition-all text-white shadow-md active:scale-95 ${isPlaying ? 'bg-amber-500 hover:bg-amber-600' : 'bg-primary hover:bg-blue-600'}`}
                    title={isPlaying ? "暂停" : "自动播放"}
                 >
                    {isPlaying ? <Pause size={20} fill="currentColor"/> : <Play size={20} fill="currentColor"/>}
                 </button>
                 <button onClick={stepForward} disabled={!result || stepIndex === result.steps.length - 1} className="p-2 hover:bg-surface-100 rounded-lg text-slate-400 hover:text-slate-700 disabled:opacity-30 transition-colors" title="下一步">
                    <SkipForward size={20} />
                 </button>
               </div>
            </div>

            {/* The Tableau */}
            {currentStep && <Tableau state={currentStep} />}

            {/* AI Insight Panel (Now Replaces the old static AI box) */}
            <div className="flex-1">
                <AIInsightPanel 
                    state={currentStep || null}
                    config={aiConfig}
                    onConfigChange={setAiConfig}
                    onGeminiKeySelect={handleGeminiKeySelection}
                    explanation={aiExplanation}
                    loading={loadingAi}
                    onGenerateExplanation={fetchExplanation}
                    onAskQuestion={handleAskQuestion}
                />
            </div>

          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

/**
 * Converts a decimal number to a fraction string.
 * Examples: 0.5 -> "1/2", -1.5 -> "-3/2", 3 -> "3", 0.333333 -> "1/3"
 */
export const toFraction = (value: number, tolerance: number = 1.0E-6): string => {
    if (Math.abs(value) < tolerance) return "0";
    if (Number.isInteger(value)) return value.toString();

    const sign = value < 0 ? "-" : "";
    let x = Math.abs(value);

    // Maximum denominator to check
    const maxDenominator = 100;

    let bestNumerator = 1;
    let bestDenominator = 1;
    let bestError = Math.abs(x - bestNumerator / bestDenominator);

    for (let d = 1; d <= maxDenominator; d++) {
        const n = Math.round(x * d);
        const error = Math.abs(x - n / d);

        if (error < bestError) {
            bestNumerator = n;
            bestDenominator = d;
            bestError = error;
        }

        if (error < tolerance) break;
    }

    if (bestDenominator === 1) return sign + bestNumerator.toString();

    // Fallback if no good fraction found or denominator too large
    if (bestDenominator > 100 && bestError > 1e-3) {
        return sign + x.toFixed(2);
    }

    return `${sign}${bestNumerator}/${bestDenominator}`;
};

import React from 'react';
import { TableauState } from '../types';
import { toFraction } from '../utils/mathUtils';

interface TableauProps {
  state: TableauState;
}

export const Tableau: React.FC<TableauProps> = ({ state }) => {
  const { tableau, variableNames, basicVariables, pivotRow, pivotCol } = state;
  const numRows = tableau.length;

  return (
    <div className="overflow-x-auto rounded-lg border border-surface-200 bg-white shadow-lg">
      <table className="w-full text-sm text-left text-slate-600">
        <thead className="text-xs uppercase bg-surface-50 text-slate-500 font-semibold tracking-wider">
          <tr>
            <th className="px-4 py-3 border-b border-surface-200">基变量 (Basic)</th>
            {variableNames.map((name, idx) => (
              <th 
                key={name} 
                className={`px-4 py-3 border-b border-surface-200 text-center ${idx === pivotCol ? 'bg-emerald-50 text-emerald-600' : ''}`}
              >
                {name === 'RHS' ? '右端项 (RHS)' : name}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {tableau.map((row, rowIndex) => {
            const isZRow = rowIndex === numRows - 1;
            const isLeaving = rowIndex === pivotRow;
            const basicVarIndex = isZRow ? -1 : basicVariables[rowIndex];
            const basicVarName = isZRow ? 'Z' : variableNames[basicVarIndex];

            return (
              <tr 
                key={rowIndex} 
                className={`
                  border-b border-surface-100 last:border-0 transition-colors duration-300
                  ${isZRow ? 'bg-surface-50 font-bold text-slate-800 border-t-2 border-t-surface-200' : ''}
                  ${isLeaving ? 'bg-red-50' : ''}
                `}
              >
                <td className="px-4 py-3 font-medium border-r border-surface-100 bg-surface-50/50">
                  {basicVarName}
                </td>
                {row.map((cell, colIndex) => {
                  const isPivot = rowIndex === pivotRow && colIndex === pivotCol;
                  const isPivotCol = colIndex === pivotCol;

                  return (
                    <td 
                      key={colIndex} 
                      className={`
                        px-4 py-3 text-center tabular-nums
                        ${isPivot ? 'bg-amber-100 text-amber-700 font-bold ring-2 ring-inset ring-amber-200' : ''}
                        ${!isPivot && isPivotCol ? 'bg-emerald-50/50' : ''}
                        ${isZRow && !isPivot ? 'text-slate-900' : ''}
                      `}
                    >
                      {toFraction(cell)}
                    </td>
                  );
                })}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

import React from 'react';
import { Calculator, ArrowRight, Sigma } from 'lucide-react';
import { TableauState } from '../types';
import { toFraction } from '../utils/mathUtils';

interface IterationTrackerProps {
  currentStep: TableauState;
  previousStep: TableauState | null;
}

export const IterationTracker: React.FC<IterationTrackerProps> = ({ currentStep, previousStep }) => {
  if (!previousStep) {
    return (
      <div className="bg-white rounded-xl border border-surface-200 shadow-sm p-5 mb-6">
        <h3 className="text-sm font-bold text-slate-700 flex items-center gap-2 mb-3">
          <Calculator size={18} className="text-blue-500" />
          迭代过程跟踪
        </h3>
        <p className="text-slate-600 text-sm">
          <span className="font-semibold bg-blue-50 text-blue-700 px-2 py-0.5 rounded">初始化</span> 
          构建初始单纯形表。所有约束转化为等式形式（引入松弛变量）。
        </p>
      </div>
    );
  }

  // Calculate the logic that happened to get from prev -> current
  const pivotRowIdx = previousStep.pivotRow!;
  const pivotColIdx = previousStep.pivotCol!;
  const pivotElement = previousStep.tableau[pivotRowIdx][pivotColIdx];
  const enteringVar = previousStep.variableNames[pivotColIdx];
  const leavingVar = previousStep.leavingVar;

  // Pivot Row Formula: NewRow = OldRow / PivotElement
  const pivotRowDisplay = (
    <div className="flex items-center gap-2 text-sm font-mono text-slate-700 bg-amber-50 p-2 rounded border border-amber-100">
      <span className="font-bold">R{pivotRowIdx + 1}'</span>
      <ArrowRight size={14} />
      <span>R{pivotRowIdx + 1} / ({toFraction(pivotElement)})</span>
    </div>
  );

  // Other Rows Formula: NewRow = OldRow - (ValInPivotCol) * NewPivotRow
  const otherRowsDisplay = previousStep.tableau.map((row, idx) => {
    if (idx === pivotRowIdx) return null; // Skip pivot row
    const valInCol = row[pivotColIdx];
    if (Math.abs(valInCol) < 1e-10) return null; // No change if 0

    const rowName = idx === previousStep.tableau.length - 1 ? 'Z' : `R${idx + 1}`;

    return (
      <div key={idx} className="flex items-center gap-2 text-sm font-mono text-slate-600">
         <span className="font-bold">{rowName}'</span>
         <span>=</span>
         <span>{rowName}</span>
         <span className="font-bold text-red-500">{valInCol > 0 ? '-' : '+'}</span>
         <span>{toFraction(Math.abs(valInCol))} × <span className="text-amber-600 font-bold">R{pivotRowIdx + 1}'</span></span>
      </div>
    );
  }).filter(Boolean);

  return (
    <div className="bg-white rounded-xl border border-surface-200 shadow-sm p-5 mb-6">
      <h3 className="text-sm font-bold text-slate-700 flex items-center gap-2 mb-4 border-b border-surface-100 pb-2">
        <Sigma size={18} className="text-blue-500" />
        步骤 {currentStep.stepIndex} 计算逻辑
      </h3>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <h4 className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">基变量变更</h4>
          <div className="flex items-center gap-4 text-sm">
             <div className="flex flex-col items-center p-3 bg-emerald-50 rounded-lg border border-emerald-100 min-w-[80px]">
                <span className="text-xs text-emerald-600 font-bold mb-1">入基</span>
                <span className="text-lg font-mono font-bold text-emerald-700">{enteringVar}</span>
             </div>
             <ArrowRight size={20} className="text-slate-300" />
             <div className="flex flex-col items-center p-3 bg-red-50 rounded-lg border border-red-100 min-w-[80px]">
                <span className="text-xs text-red-600 font-bold mb-1">出基</span>
                <span className="text-lg font-mono font-bold text-red-700">{leavingVar}</span>
             </div>
          </div>
          <p className="mt-3 text-xs text-slate-500 leading-relaxed">
            由于 <strong>{enteringVar}</strong> 在Z行系数为负且绝对值最大，选择其入基。
            通过最小比值检验，选择 <strong>{leavingVar}</strong> 所在的行作为主元行。
          </p>
        </div>

        <div>
           <h4 className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">行变换公式 (高斯消元)</h4>
           <div className="space-y-2">
              <div className="mb-2">
                <span className="text-xs text-amber-600 font-bold mb-1 block">1. 归一化主元行:</span>
                {pivotRowDisplay}
              </div>

              {otherRowsDisplay.length > 0 && (
                  <div>
                    <span className="text-xs text-slate-500 font-bold mb-1 block">2. 消去其他行对应列:</span>
                    <div className="bg-surface-50 p-2 rounded border border-surface-100 space-y-1">
                        {otherRowsDisplay}
                    </div>
                  </div>
              )}
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, SkipForward, SkipBack, RotateCcw, 
  CheckCircle, AlertCircle, TrendingUp
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

import { Tableau } from './components/Tableau';
import { ProblemInput } from './components/ProblemInput';
import { AIInsightPanel } from './components/AIInsightPanel';
import { IterationTracker } from './components/IterationTracker';
import { solveSimplex } from './services/simplexEngine';
import { generateExplanation, generateRandomProblem, askAIQuestion } from './services/geminiService';
import { LPProblem, SimplexResult, SimplexStatus, AIConfig } from './types';

// Default Problem
const DEFAULT_PROBLEM: LPProblem = {
  numVariables: 2,
  numConstraints: 2,
  objective: [3, 4],
  constraints: [
    [1, 2],
    [2, 1]
  ],
  rhs: [10, 8]
};

const App: React.FC = () => {
  const [problem, setProblem] = useState<LPProblem>(DEFAULT_PROBLEM);
  const [result, setResult] = useState<SimplexResult | null>(null);
  const [stepIndex, setStepIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  // AI State
  const [aiExplanation, setAiExplanation] = useState<string>("");
  const [loadingAi, setLoadingAi] = useState(false);
  const [aiConfig, setAiConfig] = useState<AIConfig>({
    provider: 'gemini',
    deepSeekKey: ''
  });

  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    handleSolve(problem);
  }, []);

  const handleSolve = (p: LPProblem) => {
    const res = solveSimplex(p);
    setProblem(p);
    setResult(res);
    setStepIndex(0);
    setIsPlaying(false);
    // Reset explanation on new solve
    setAiExplanation("");
  };

  const handleGeminiKeySelection = async () => {
    if (window.aistudio) {
        await window.aistudio.openSelectKey();
    }
  };

  const checkKeyReady = async (): Promise<boolean> => {
    if (aiConfig.provider === 'gemini') {
        if (window.aistudio) {
             const hasKey = await window.aistudio.hasSelectedApiKey();
             if (!hasKey) {
                 setAiExplanation("请在 AI 洞察面板中点击齿轮图标，配置 Google API Key。");
                 return false;
             }
             return true;
        }
        return false;
    } else {
        if (!aiConfig.deepSeekKey) {
            setAiExplanation("请在 AI 洞察面板中点击齿轮图标，输入 DeepSeek API Key。");
            return false;
        }
        return true;
    }
  };

  const handleRandom = async () => {
    setLoadingAi(true);
    const ready = await checkKeyReady();
    if (!ready) {
        setLoadingAi(false);
        return;
    }

    const newProb = await generateRandomProblem(aiConfig);
    setLoadingAi(false);
    if (newProb) {
        setProblem(newProb);
        handleSolve(newProb);
    }
  };

  const fetchExplanation = async () => {
    const state = result?.steps[stepIndex];
    if (!state) return;

    setLoadingAi(true);
    const ready = await checkKeyReady();
    if (!ready) {
        setLoadingAi(false);
        return;
    }

    const text = await generateExplanation(state, aiConfig);
    setAiExplanation(text);
    setLoadingAi(false);
  };

  const handleAskQuestion = async (question: string) => {
    const state = result?.steps[stepIndex];
    if (!state) return;

    setLoadingAi(true);
    const ready = await checkKeyReady();
    if (!ready) {
        setLoadingAi(false);
        return;
    }

    const text = await askAIQuestion(question, state, aiConfig);
    setAiExplanation(text);
    setLoadingAi(false);
  }

  const currentStep = result?.steps[stepIndex];
  const previousStep = stepIndex > 0 && result ? result.steps[stepIndex - 1] : null;

  // Auto-play Logic
  useEffect(() => {
    if (isPlaying && result) {
      timerRef.current = window.setInterval(() => {
