import { GoogleGenAI, Type } from "@google/genai";
import { TableauState, AIConfig } from '../types';

// Helper to get Gemini Client with the selected key
const getGeminiClient = () => {
  const apiKey = process.env.API_KEY; 
  // We throw here so App.tsx can catch it and prompt the user
  if (!apiKey) throw new Error("API_KEY_MISSING");
  return new GoogleGenAI({ apiKey });
};

const formatContext = (state: TableauState) => {
    return `
    当前单纯形表状态:
    - 阶段: 步骤 ${state.stepIndex}
    - 状态: ${state.status}
    - 目标函数值 Z: ${state.zValue.toFixed(2)}
    - 变量列表: ${state.variableNames.join(', ')}
    - 基变量索引: ${state.basicVariables.join(', ')}
    - 入基变量: ${state.enteringVar || "无"}
    - 出基变量: ${state.leavingVar || "无"}
    `;
};

export const generateExplanation = async (state: TableauState, config: AIConfig): Promise<string> => {
  const prompt = `
    你是一位乐于助人的运筹学导师。请用中文解释单纯形法当前的步骤。

    ${formatContext(state)}
    - 步骤描述: ${state.description}

    如果是“最优解”，请解释最终Z值的含义。
    如果是“计算中”，请解释为什么选择该入基变量（通常是Z行中负值最大）和出基变量（最小比值检验）。
    请保持简洁（不超过2句话），语气鼓励。
  `;

  return await callAI(prompt, config);
};

export const askAIQuestion = async (question: string, state: TableauState, config: AIConfig): Promise<string> => {
    const prompt = `
    你是一位专业的运筹学助手。用户正在查看单纯形法的求解过程。

    上下文信息：
    ${formatContext(state)}

    用户的问题是： "${question}"

    请结合上面的上下文，用通俗易懂的中文回答用户的问题。如果问题与当前步骤无关，请尝试从运筹学角度回答。
    `;
    return await callAI(prompt, config);
}

// Unified AI Caller
const callAI = async (prompt: string, config: AIConfig): Promise<string> => {
    if (config.provider === 'deepseek') {
      if (!config.deepSeekKey) return "请在设置中输入 DeepSeek API Key。";

      try {
          const response = await fetch("https://api.deepseek.com/chat/completions", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "Authorization": `Bearer ${config.deepSeekKey}`
            },
            body: JSON.stringify({
              model: "deepseek-chat",
              messages: [
                { role: "system", content: "你是一位乐于助人的数学导师。" },
                { role: "user", content: prompt }
              ],
              stream: false
            })
          });

          if (!response.ok) throw new Error(`DeepSeek API 错误: ${response.statusText}`);
          const data = await response.json();
          return data.choices[0]?.message?.content || "未返回解释。";
      } catch (error: any) {
          console.error("DeepSeek Error:", error);
          return `DeepSeek 错误: ${error.message}`;
      }

    } else {
      // Gemini Logic - Let errors bubble up to be handled by UI key selector
      const ai = getGeminiClient();
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
      });
      return response.text || "无法生成解释。";
    }
}

export const generateRandomProblem = async (config: AIConfig): Promise<any> => {
   const schema = {
        type: Type.OBJECT,
        properties: {
            numVariables: { type: Type.INTEGER },
            numConstraints: { type: Type.INTEGER },
            objective: { 
                type: Type.ARRAY, 
                items: { type: Type.INTEGER } 
            },
            constraints: { 
                type: Type.ARRAY, 
                items: { 
                    type: Type.ARRAY, 
                    items: { type: Type.INTEGER } 
                } 
            },
            rhs: { 
                type: Type.ARRAY, 
                items: { type: Type.INTEGER } 
            }
        },
        required: ["numVariables", "numConstraints", "objective", "constraints", "rhs"]
   };

   const userPrompt = "生成一个有效、可解的线性规划最大化问题。包含2或3个变量，2或3个约束。系数应为1到10之间的小整数，以便于可视化。不要生成无界解的问题。";

   if (config.provider === 'deepseek') {
        if (!config.deepSeekKey) return null;
        try {
            const response = await fetch("https://api.deepseek.com/chat/completions", {
                method: "POST",
                headers: {
                  "Content-Type": "application/json",
                  "Authorization": `Bearer ${config.deepSeekKey}`
                },
                body: JSON.stringify({
                  model: "deepseek-chat",
                  messages: [
                    { role: "system", content: "你是一个数学题目生成器。只输出有效的JSON。" },
                    { role: "user", content: userPrompt + " 只返回符合此结构的JSON对象: {numVariables: int, numConstraints: int, objective: [int], constraints: [[int]], rhs: [int]}." }
                  ]
                })
            });
            const data = await response.json();
            const content = data.choices[0]?.message?.content;
            const jsonStr = content.replace(/```json/g, '').replace(/```/g, '').trim();
            return JSON.parse(jsonStr);
        } catch (e) {
            console.error(e);
            return null;
        }

    } else {
        // Gemini - Let errors bubble up
        const ai = getGeminiClient();
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: userPrompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema
            }
        });
        return JSON.parse(response.text);
    }
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, SkipForward, SkipBack, RotateCcw, 
  CheckCircle, AlertCircle, TrendingUp, FastForward
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

import { Tableau } from './components/Tableau';
import { ProblemInput } from './components/ProblemInput';
import { AIInsightPanel } from './components/AIInsightPanel';
import { IterationTracker } from './components/IterationTracker';
import { solveSimplex } from './services/simplexEngine';
import { generateExplanation, generateRandomProblem, askAIQuestion } from './services/geminiService';
import { LPProblem, SimplexResult, SimplexStatus, AIConfig } from './types';

// Default Problem
const DEFAULT_PROBLEM: LPProblem = {
  numVariables: 2,
  numConstraints: 2,
  objective: [3, 4],
  constraints: [
    [1, 2],
    [2, 1]
  ],
  rhs: [10, 8]
};

const App: React.FC = () => {
  const [problem, setProblem] = useState<LPProblem>(DEFAULT_PROBLEM);
  const [result, setResult] = useState<SimplexResult | null>(null);
  const [stepIndex, setStepIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  // AI State
  const [aiExplanation, setAiExplanation] = useState<string>("");
  const [loadingAi, setLoadingAi] = useState(false);
  const [isGeminiKeySet, setIsGeminiKeySet] = useState(false);
  const [aiConfig, setAiConfig] = useState<AIConfig>({
    provider: 'gemini',
    deepSeekKey: ''
  });

  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    handleSolve(problem);

    // Check for existing Gemini API key on mount
    if (window.aistudio) {
        window.aistudio.hasSelectedApiKey().then((hasKey: boolean) => {
            setIsGeminiKeySet(hasKey);
        });
    }
  }, []);

  const handleSolve = (p: LPProblem) => {
    const res = solveSimplex(p);
    setProblem(p);
    setResult(res);
    setStepIndex(0);
    setIsPlaying(false);
    // Reset explanation on new solve
    setAiExplanation("");
  };

  const handleGeminiKeySelection = async () => {
    if (window.aistudio) {
        try {
            await window.aistudio.openSelectKey();
            // Race condition mitigation: assume success immediately
            setIsGeminiKeySet(true);
            setAiExplanation(""); // Clear any previous error messages
        } catch (e) {
            console.error("Key selection failed", e);
        }
    }
  };

  const handleAIError = async (error: any) => {
      console.error("AI Error detected:", error);
      const errorMsg = error.toString();

      // Check for specific error indicating missing/invalid key or "Requested entity was not found"
      if (
          errorMsg.includes("Requested entity was not found") || 
          errorMsg.includes("API_KEY_MISSING") ||
          errorMsg.includes("403") ||
          errorMsg.includes("401")
      ) {
          setIsGeminiKeySet(false);
          setAiExplanation("API Key 无效或过期，正在重新打开选择窗口...");
          await handleGeminiKeySelection();
      } else {
          setAiExplanation(`AI 错误: ${error.message || "未知错误"}`);
      }
  };

  const checkKeyReady = async (): Promise<boolean> => {
    if (aiConfig.provider === 'gemini') {
        if (!isGeminiKeySet) {
             setAiExplanation("请点击齿轮图标，并选择 Google API Key。");
             return false;
        }
        return true;
    } else {
        if (!aiConfig.deepSeekKey) {
            setAiExplanation("请在 AI 洞察面板中点击齿轮图标，输入 DeepSeek API Key。");
            return false;
        }
        return true;
    }
  };

  const handleRandom = async () => {
    setLoadingAi(true);
    const ready = await checkKeyReady();
    if (!ready) {
        setLoadingAi(false);
        // If Gemini and not set, try opening the dialog immediately for convenience
        if (aiConfig.provider === 'gemini' && !isGeminiKeySet) {
             await handleGeminiKeySelection();
        }
        return;
    }

    try {
        const newProb = await generateRandomProblem(aiConfig);
        if (newProb) {
            setProblem(newProb);
            handleSolve(newProb);
            setAiExplanation("已生成新的随机问题。");
        }
    } catch (e) {
        await handleAIError(e);
    } finally {
        setLoadingAi(false);
    }
  };

  const fetchExplanation = async () => {
    const state = result?.steps[stepIndex];
    if (!state) return;

    setLoadingAi(true);
    const ready = await checkKeyReady();
    if (!ready) {
        setLoadingAi(false);
        return;
    }

    try {
        const text = await generateExplanation(state, aiConfig);
        setAiExplanation(text);
    } catch (e) {
        await handleAIError(e);
    } finally {
        setLoadingAi(false);
    }
  };

  const handleAskQuestion = async (question: string) => {
    const state = result?.steps[stepIndex];
    if (!state) return;

    setLoadingAi(true);
    const ready = await checkKeyReady();
    if (!ready) {
        setLoadingAi(false);
        return;
    }

    try {
        const text = await askAIQuestion(question, state, aiConfig);
        setAiExplanation(text);
    } catch (e) {
        await handleAIError(e);
    } finally {
        setLoadingAi(false);
    }
  }

  const currentStep = result?.steps[stepIndex];
  const previousStep = stepIndex > 0 && result ? result.steps[stepIndex - 1] : null;

  // Auto-play Logic
  useEffect(() => {
    if (isPlaying && result) {
      timerRef.current = window.setInterval(() => {
        setStepIndex(prev => {
          if (prev < result.steps.length - 1) {
             return prev + 1;
          } else {
            setIsPlaying(false);
            return prev;
          }
        });
      }, 1500); 
    } else if (timerRef.current) {
      clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isPlaying, result]);

  const stepForward = () => result && stepIndex < result.steps.length - 1 && setStepIndex(stepIndex + 1);
  const stepBack = () => stepIndex > 0 && setStepIndex(stepIndex - 1);

  const jumpToOptimal = () => {
    if (result && result.steps.length > 0) {
        setStepIndex(result.steps.length - 1);
        setIsPlaying(false);
    }
  };

  const chartData = result?.steps.map((s, i) => ({ step: i, z: s.zValue })) || [];

  return (
    <div className="min-h-screen bg-surface-50 text-slate-800 font-sans pb-20">

      {/* Header */}
      <header className="bg-white border-b border-surface-200 sticky top-0 z-50 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center text-white font-bold shadow-md shadow-blue-500/30">
              S
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">
              单纯形<span className="text-primary">可视化</span> (SimplexFlow)
            </h1>
          </div>
          <div className="hidden md:flex text-sm text-slate-500 gap-4 font-medium">
             <span className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full bg-emerald-500"></span> 入基变量</span>
             <span className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full bg-red-500"></span> 出基变量</span>
             <span className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-full bg-amber-500"></span> 主元</span>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
          {/* Left Column: Controls & Charts */}
          <div className="lg:col-span-1 space-y-6">
             <ProblemInput 
                initialProblem={problem} 
                onSolve={handleSolve}
                onRandom={handleRandom}
             />

             {/* Progress Chart */}
             <div className="bg-white p-6 rounded-xl border border-surface-200 shadow-sm">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wide mb-4 flex items-center gap-2">
                    <TrendingUp size={16} className="text-primary"/> 优化路径 (Objective Z)
                </h3>
                <div className="h-40 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <LineChart data={chartData}>
                            <XAxis dataKey="step" hide />
                            <YAxis width={30} stroke="#94a3b8" fontSize={10} tickFormatter={(v) => v.toFixed(1)}/>
                            <Tooltip 
                                contentStyle={{backgroundColor: '#fff', border: '1px solid #e2e8f0', borderRadius: '8px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                                itemStyle={{color: '#3b82f6', fontWeight: 600}}
                            />
                            <Line 
                                type="monotone" 
                                dataKey="z" 
                                stroke="#3b82f6" 
                                strokeWidth={3} 
                                dot={{fill: '#3b82f6', strokeWidth: 2, r: 4}} 
                                activeDot={{r: 6, stroke: '#fff', strokeWidth: 2}} 
                            />
                        </LineChart>
                    </ResponsiveContainer>
                </div>
             </div>
          </div>

          {/* Right Column: Visualization & AI */}
          <div className="lg:col-span-2 space-y-6 flex flex-col">

            {/* Status Bar */}
            <div className="flex items-center justify-between bg-white p-4 rounded-xl border border-surface-200 shadow-sm">
